#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";

function normText(value = "") {
  return String(value || "").trim();
}

function normArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(values = []) {
  return [...new Set(normArray(values).map((row) => normText(row)).filter(Boolean))];
}

function buildBundle(trainingSet = {}) {
  const source = trainingSet?.crossEffectSharedSettingLearning?.sharedSettingOutcomeMemory;
  const settingsByName = Object.fromEntries(
    Object.entries(source && typeof source === "object" ? source : {})
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([settingName, entries]) => [
        normText(settingName),
        normArray(entries).map((row) => ({
          appliedValue: row?.appliedValue,
          sampleCount: Number(row?.sampleCount || 0),
          successfulUses: Number(row?.successfulUses || 0),
          failedUses: Number(row?.failedUses || 0),
          effectNames: unique(row?.effectNames),
          favoredScopes: unique(row?.favoredScopes),
          favoredSignals: unique(row?.favoredSignals),
          cautionSignals: unique(row?.cautionSignals)
        }))
      ])
  );
  return {
    artifactType: "sequencer_cross_effect_shared_settings_bundle",
    artifactVersion: "1.0",
    generatedAt: new Date().toISOString(),
    sourceArtifactType: normText(trainingSet?.artifactType),
    sourceArtifactVersion: normText(trainingSet?.artifactVersion),
    settingCount: Object.keys(settingsByName).length,
    settingsByName
  };
}

function writeJsModule(bundle, outputPath) {
  const text = JSON.stringify(bundle, null, 2);
  fs.writeFileSync(
    outputPath,
    "// Auto-generated by scripts/sequencer-render-training/tooling/export-cross-effect-shared-settings-bundle.mjs\n"
      + "export const CROSS_EFFECT_SHARED_SETTINGS_BUNDLE = "
      + text
      + ";\n"
  );
}

function main() {
  const args = process.argv.slice(2);
  const inputIndex = args.indexOf("--input");
  const outputIndex = args.indexOf("--output");
  if (inputIndex < 0 || outputIndex < 0 || !args[inputIndex + 1] || !args[outputIndex + 1]) {
    throw new Error("Usage: node export-cross-effect-shared-settings-bundle.mjs --input <training-set.json> --output <bundle.js>");
  }
  const inputPath = path.resolve(args[inputIndex + 1]);
  const outputPath = path.resolve(args[outputIndex + 1]);
  const trainingSet = JSON.parse(fs.readFileSync(inputPath, "utf8"));
  const bundle = buildBundle(trainingSet);
  writeJsModule(bundle, outputPath);
  process.stdout.write(`${JSON.stringify({ output: outputPath, settingCount: bundle.settingCount }, null, 2)}\n`);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  main();
}

export { buildBundle };
